#include<bits/stdc++.h>
using namespace std;
string a_x_b(string A,string B,string ans=""){
	int a[100000]={0},b[100000]={0},c[100000]={0};
	int lena=A.size(),lenb=B.size();
    for(int i=lena-1;i>=0;i--)a[lena-i]=A[i]-'0';
    for(int i=lenb-1;i>=0;i--)b[lenb-i]=B[i]-'0';
    int len=lena+lenb;
    for(int i=1;i<=lena;i++)
        for(int j=1;j<=lenb;j++)c[i+j-1]+=a[i]*b[j];
    for(int i=1;i<=len;i++)c[i+1]+=c[i]/10,c[i]%=10;
    while(c[len]==0)len--;
    for(int i=max(1,len);i>=1;i--)ans+=char(c[i]+'0');
    return ans;
}
string pow(string a,int n,string ans="1"){
	while(n--)ans=a_x_b(ans,a);
	return ans;
}
int f(string s){
	int j=0,o=0;
	for(int i=0;i<s.size();i++)j+=int(s[i]-'0')%2,o+=int(s[i]-'0'+1)%2;
	return j-o;
}
int main(void){
	string a;
	int n;
    cin>>a>>n;
    cout<<f(pow(a,n));
	return false;
}
